const body = $input.item.json.body;

const currentMessage = body.message || '';
const history        = Array.isArray(body.history) ? body.history : [];

// Construire le tableau messages : system + historique + message actuel
const messages = [
  {
    role: 'system',
    content: `Tu es l'assistant virtuel de CampusLink, une plateforme qui connecte étudiants et tuteurs pour des services éducatifs.\n\nTon rôle :\n- Aider les utilisateurs à naviguer sur la plateforme\n- Répondre aux questions sur le fonctionnement\n- Donner des conseils pour créer de bonnes publications/services\n- Être amical, patient et concis\n\nRègles de réponse :\n1. Réponds en 2-4 phrases maximum (sauf si explication technique nécessaire)\n2. Utilise des emojis pertinents (max 2 par message)\n3. Si tu ne sais pas, oriente vers le support humain\n4. Propose des actions concrètes quand possible\n5. Sois encourageant et positif`
  },
  ...history,
  {
    role: 'user',
    content: currentMessage
  }
];

const openRouterBody = {
  model: 'openai/gpt-3.5-turbo',
  temperature: 0.7,
  max_tokens: 300,
  messages: messages
};

return {
  json: {
    openRouterBody: JSON.stringify(openRouterBody),
    user_id: body.user_id,
    user_message: currentMessage
  }
};

const response     = $input.item.json;
const botMessage   = response.choices[0].message.content;
const prevNode     = $('Construire Requête').item.json;

return {
  json: {
    response:     botMessage,
    user_id:      prevNode.user_id,
    user_message: prevNode.user_message,
    timestamp:    new Date().toISOString()
  }
};
